('gill_update','Gillingham Warehouse Update','Gillingham','Starts the Gillingham warehouse update chain.','Daily at 22:30','Server local time',NULL,'Gillingham operational data becomes stale.','https://github.com/benthud82/gillingham','Production chain: gill_update.py -> update_GILL.bat -> update_master.php.',1,1,'2026-07-17 00:00:00',0,0),
('hep_update','HEP Warehouse Update','HEP','Runs the HEP warehouse update chain.','Daily at 21:30','Server local time',NULL,'HEP operational data may become stale.','','Production chain: hep_update.py -> update_hep.bat -> HEP MySQLUpdates PHP table scripts.',1,1,'2026-07-17 00:00:00',0,0),
('ukgill_update_all_tables','UK Gill Full Table Update','EMEA UK Gill','Refreshes UK Gill base data, demand analytics, optimization outputs, and recommendation history.','Daily at 22:10 Mon-Fri','Server local time',NULL,'UK Gill slotting and reporting surfaces may show stale warehouse data.','https://github.com/benthud82/emea_ukgill_logic','Production chain traced through update_all_tables.bat into PHP table updates and heatmap_recommender.py.',1,1,'2026-07-17 00:00:00',0,0),
('breaklunch_ftp_1','NextView Daily Operations Export','Break/Lunch and NextView','Exports break/lunch, EOD, slow-moving replenishment, and shorts data to NextView.','Daily at 05:01','Server local time',NULL,'NextView daily operational files become stale; this job does not write MySQL.','https://github.com/benthud82/breaklunch','Python, batch, PHP, source queries, and FTP output traced from GitHub.',1,1,'2026-07-12 00:00:00',0,0),
('breaklunch_ftp_2','NextView Canada Pack/Pick Export','Break/Lunch and NextView','Exports NOTL and Calgary pack, pick, case, and parts data to NextView.','Daily at 23:00','Server local time',NULL,'NextView Canada operational files become stale; this job does not write MySQL.','https://github.com/benthud82/breaklunch','Python, batch, PHP, source queries, and FTP output traced from GitHub.',1,1,'2026-07-12 00:00:00',0,0),
